import React from 'react';
import { clsx } from 'clsx';
import { useScrollReveal } from '../hooks';
import { PROCESS_STEPS } from '../utils';
import { SectionHeader } from './ui';

const ProcessCard = ({ step }) => (
  <div className="text-center group">
    <div className="w-20 h-20 mx-auto mb-8 flex items-center justify-center bg-white/5 border border-white/10 rounded-full font-serif text-2xl italic text-gold relative transition-all duration-500 ease-out-expo group-hover:bg-gold group-hover:text-primary group-hover:scale-110 group-hover:border-gold">
      {step.number}
    </div>
    <h3 className="text-lg font-semibold mb-3">{step.title}</h3>
    <p className="text-[15px] text-white/50 leading-relaxed">{step.description}</p>
  </div>
);

const Process = () => {
  const [ref, isVisible] = useScrollReveal({ threshold: 0.3 });

  return (
    <section className="section section-dark" id="process">
      <div className="container">
        <SectionHeader
          number="02"
          title="How It"
          titleHighlight="Works"
          description="Getting started takes just minutes. Here's how we protect your important documents."
          dark
        />

        <div
          ref={ref}
          className={clsx(
            'relative opacity-0 translate-y-10 transition-all duration-700 ease-out-expo',
            isVisible && 'opacity-100 translate-y-0'
          )}
        >
          {/* Timeline Line - Desktop */}
          <div className="hidden lg:block absolute top-[60px] left-0 right-0 h-px bg-white/10" />
          <div
            className={clsx(
              'hidden lg:block absolute top-[60px] left-0 h-px bg-gold transition-all duration-[1.5s] ease-out-expo',
              isVisible ? 'w-full' : 'w-0'
            )}
          />

          {/* Steps Grid */}
          <div className="grid sm:grid-cols-2 lg:grid-cols-4 gap-8 relative">
            {PROCESS_STEPS.map((step) => (
              <ProcessCard key={step.number} step={step} />
            ))}
          </div>
        </div>
      </div>
    </section>
  );
};

export default Process;
